import torch

class SGDMomentum:
    def __init__(self, params: list[torch.nn.Parameter], lr: float = 0.01, beta: float = 0.9):
        self.params = list(params)
        self.lr = lr
        self.beta = beta
        self.velocity = [torch.zeros_like(p) for p in self.params]

    def step(self) -> None:
        for v, p in zip(self.velocity, self.params):
            if p.grad is None:
                continue
            v.mul_(self.beta).add_(p.grad)
            p.data -= self.lr * v

    def zero_grad(self) -> None:
        for p in self.params:
            if p.grad is not None:
                p.grad = None

